const response = items[0].json.output || '';
const CHAR_LIMIT = 6000;

// Pass through if under limit
if (response.length <= CHAR_LIMIT) {
  return [{ json: { output: response } }];
}

// Detect Plan Mode response by section headers
const isPlanMode = /EXECUTIVE SUMMARY/i.test(response) &&
                   /STRATEGIC IMPLICATIONS/i.test(response);

if (!isPlanMode) {
  return [{ json: { output: response.substring(0, CHAR_LIMIT) + '\n\n*[Response truncated — query the agent directly for the full report.]*' } }];
}

let out = '';

// --- EXECUTIVE SUMMARY: first 5 bullets ---
const execMatch = response.match(/\*?\*?EXECUTIVE SUMMARY\*?\*?([\s\S]*?)(?=\n#+\s|\n\*\*(?:COMPETITOR|\[TOPIC|ZIP|COHORT|PAYER|COMPETITIVE|STRATEGIC)|\n\|)/i);
if (execMatch) {
  const bullets = (execMatch[1].match(/^[-*]\s.+$/gm) || []).slice(0, 5);
  out += '**EXECUTIVE SUMMARY**\n\n' + bullets.join('\n') + '\n\n';
}

// --- TOPIC TABLE: first markdown table found after exec summary ---
const tableMatch = response.match(/(\|.+\|\n\|[-| :]+\|\n(?:\|.+\|\n?)+)/);
if (tableMatch) {
  // Limit table to 12 rows (header + separator + 10 data rows)
  const rows = tableMatch[1].trim().split('\n');
  out += rows.slice(0, 12).join('\n') + '\n\n';
}

// --- COMPETITIVE / MARKET ANALYSIS: first 3 paragraphs ---
const analysisMatch = response.match(/COMPETITIVE\s*[\/]?\s*MARKET ANALYSIS([\s\S]*?)(?=\*?\*?STRATEGIC IMPLICATIONS)/i);
if (analysisMatch) {
  const paras = analysisMatch[1].trim().split(/\n{2,}/).filter(p => p.trim().length > 80);
  out += '**COMPETITIVE / MARKET ANALYSIS**\n\n' + paras.slice(0, 3).join('\n\n') + '\n\n';
}

// --- STRATEGIC IMPLICATIONS: first 5 bullets ---
const implMatch = response.match(/STRATEGIC IMPLICATIONS([\s\S]*)$/i);
if (implMatch) {
  const bullets = (implMatch[1].match(/^[-*]\s[\s\S]*?(?=\n[-*]\s|\n\n\n|$)/gm) || []).slice(0, 5);
  out += '**STRATEGIC IMPLICATIONS**\n\n' + bullets.join('\n\n');
}

// Fallback if parsing failed
if (out.trim().length < 200) {
  out = response.substring(0, CHAR_LIMIT) + '\n\n*[Truncated for delivery.]*';
}

return [{ json: { output: out.trim() } }];
